using System;
using System.Linq;
using System.Collections.Generic;

class Program
{
    static void Main()
    {
        var employees = new List<(string Name, string Dept, int Salary)>
        {
            ("Alice", "IT", 70000),
            ("Bob", "HR", 50000),
            ("Charlie", "IT", 80000),
            ("Diana", "HR", 55000)
        };

        var result = employees
            .Where(e => e.Salary > 60000)
            .GroupBy(e => e.Dept)
            .Select(g => new {
                Department = g.Key,
                Count = g.Count(),
                AvgSalary = g.Average(e => e.Salary)
            });

        foreach (var item in result)
            Console.WriteLine($"{item.Department}: {item.Count} employees, avg {item.AvgSalary:C}");
    }
}
